INSERT INTO `kategoriler` VALUES ('anlasmalar','Diplomasi ve Anlaşmalar','Kılıçla kazanılan zaferlerin kalemle tescillendiği tarihi belgeler','fa-solid fa-handshake'),('cografya','Türk Coğrafyası','Tanrı Dağları\'ndan Viyana kapılarına, Adriyatik\'ten Çin Seddi\'ne uzanan miras','fa-solid fa-map-location-dot'),('denizcilik','Türk Denizciliği','Kadırgalardan zırhlılara: Mavi Vatan\'ın şanlı tarihçesi','fa-solid fa-anchor'),('hukuk','Hukuk ve Töre','İl gider töre kalır: Türk devlet geleneğinde adaletin sarsılmaz yeri','fa-solid fa-scale-balanced'),('kultur','Kültür ve Sanat','Bozkırın sert rüzgarından sarayın ince ruhuna medeniyet yolculuğu','fa-solid fa-palette'),('savaslar','Büyük Türk Savaşları','Tarihin akışını değiştiren, zaferle sonuçlanan kritik dönüm noktaları','fa-solid fa-person-rifle');
