  `id` int NOT NULL AUTO_INCREMENT,
  `ad` varchar(255) DEFAULT NULL,
  `soyad` varchar(255) DEFAULT NULL,
  `kadi` varchar(255) DEFAULT NULL,
  `eposta` varchar(255) DEFAULT NULL,
  `sifre` varchar(255) DEFAULT NULL,
  `puan` int DEFAULT '0',
  `rol` varchar(255) DEFAULT 'uye',
  `kayit_tarihi` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `kadi` (`kadi`),
  UNIQUE KEY `kadi_2` (`kadi`),
  UNIQUE KEY `kadi_3` (`kadi`),
  UNIQUE KEY `kadi_4` (`kadi`),
  UNIQUE KEY `kadi_5` (`kadi`),
  UNIQUE KEY `kadi_6` (`kadi`),
  UNIQUE KEY `kadi_7` (`kadi`),
  UNIQUE KEY `kadi_8` (`kadi`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
